WITH policy_rows AS (SELECT 10 AS sort_key, 'profiles_policy'::text AS audit_section, policyname::text AS item_name, cmd::text AS detail_1, array_to_string(roles, ',')::text AS detail_2, ('USING=' || COALESCE(qual, '<none>') || ' | CHECK=' || COALESCE(with_check, '<none>'))::text AS detail_3 FROM pg_policies WHERE schemaname = 'public' AND tablename = 'profiles'), column_rows AS (SELECT 20 AS sort_key, 'profiles_column'::text AS audit_section, column_name::text AS item_name, data_type::text AS detail_1, is_nullable::text AS detail_2, COALESCE(column_default, '<none>')::text AS detail_3 FROM information_schema.columns WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name IN ('id','role','department','is_active','is_approved','deleted_at','created_at')), trigger_rows AS (SELECT 30 AS sort_key, 'profiles_trigger'::text AS audit_section, trigger_name::text AS item_name, event_manipulation::text AS detail_1, action_timing::text AS detail_2, action_statement::text AS detail_3 FROM information_schema.triggers WHERE event_object_schema = 'public' AND event_object_table = 'profiles'), expected_rpc AS (SELECT * FROM (VALUES ('admin_deactivate_profiles_v1','public.admin_deactivate_profiles_v1(uuid[],text)'), ('admin_restore_profiles_v1','public.admin_restore_profiles_v1(uuid[],text)'), ('admin_list_deactivated_profiles_v1','public.admin_list_deactivated_profiles_v1()')) AS v(item_name, signature)), rpc_rows AS (SELECT 40 AS sort_key, 'account_action_rpc'::text AS audit_section, e.item_name::text, CASE WHEN to_regprocedure(e.signature) IS NULL THEN 'missing' ELSE has_function_privilege('anon', to_regprocedure(e.signature), 'EXECUTE')::text END AS detail_1, CASE WHEN to_regprocedure(e.signature) IS NULL THEN 'missing' ELSE has_function_privilege('authenticated', to_regprocedure(e.signature), 'EXECUTE')::text END AS detail_2, e.signature::text AS detail_3 FROM expected_rpc e), prerequisite_rows AS (SELECT 50 AS sort_key, 'prerequisite'::text AS audit_section, 'is_admin_function'::text AS item_name, COALESCE(to_regprocedure('public.is_admin()')::text, 'missing') AS detail_1, '<none>'::text AS detail_2, '<none>'::text AS detail_3 UNION ALL SELECT 51, 'prerequisite', 'super_admins_table', COALESCE(to_regclass('public.super_admins')::text, 'missing'), '<none>', '<none>'), summary_rows AS (SELECT 60 AS sort_key, 'profiles_summary'::text AS audit_section, 'counts'::text AS item_name, (count(*) FILTER (WHERE deleted_at IS NULL))::text AS detail_1, (count(*) FILTER (WHERE deleted_at IS NOT NULL))::text AS detail_2, (count(*) FILTER (WHERE deleted_at IS NULL AND COALESCE(is_active,false) AND COALESCE(is_approved,false)))::text AS detail_3 FROM public.profiles) SELECT audit_section, item_name, detail_1, detail_2, detail_3 FROM (SELECT * FROM policy_rows UNION ALL SELECT * FROM column_rows UNION ALL SELECT * FROM trigger_rows UNION ALL SELECT * FROM rpc_rows UNION ALL SELECT * FROM prerequisite_rows UNION ALL SELECT * FROM summary_rows) audit ORDER BY sort_key, item_name;
